using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI ---
// ChatClientAgent automatically wraps the client with FunctionInvokingChatClient,
// so we only need the base provider client here.
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var notebook = new ResearchNotebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            WebSearchTool.SearchAsync(query),
        "web_search",
        "Searches the web for a given query and returns results with titles, URLs, and snippets."),

    AIFunctionFactory.Create(
        ([Description("A concise title for the note")] string title,
         [Description("The detailed content of the note")] string content,
         [Description("The source URL, if applicable")] string? source) =>
        {
            notebook.AddNote(title, content, source);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note with a title, content, and optional source URL. Use this to record key findings during research."),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "get_notes",
        "Retrieves all saved research notes collected so far."),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research assistant. When given a topic:
        1. Search the web multiple times with different queries to gather diverse information.
        2. Save each key finding as a note using the save_note tool.
        3. After gathering enough information (at least 3-5 searches), review your notes with get_notes.
        4. Provide a well-structured summary with sections, covering background, key points, and recent developments.

        Be thorough but focused. Cite sources where possible.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking structured notes.",
    tools: tools);

// --- Run ---
Console.WriteLine("🔍 Research Agent");
Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("\n> ");

while (Console.ReadLine() is { } topic && !topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Write("> ");
        continue;
    }

    Console.WriteLine($"\n⏳ Researching: {topic}...\n");

    notebook.Clear();

    var session = await agent.CreateSessionAsync();
    var runOptions = new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    });

    var response = await agent.RunAsync(
        $"Research the following topic thoroughly and provide a comprehensive summary: {topic}",
        session,
        runOptions);

    Console.WriteLine("═══════════════════════════════════════");
    Console.WriteLine("📋 RESEARCH SUMMARY");
    Console.WriteLine("═══════════════════════════════════════");
    Console.WriteLine(response.Text);
    Console.WriteLine("═══════════════════════════════════════");

    if (notebook.Count > 0)
    {
        Console.WriteLine($"\n📝 {notebook.Count} note(s) collected during research.\n");
    }

    Console.Write("> ");
}

Console.WriteLine("Goodbye!");

// =============================================================================
// Web Search Tool
// =============================================================================
static class WebSearchTool
{
    /// <summary>
    /// Simulated web search. Replace the body of this method with a real search API
    /// (e.g., Bing Search API, Google Custom Search, or Brave Search) for production use.
    /// </summary>
    public static async Task<string> SearchAsync(string query)
    {
        await Task.Delay(50); // Simulate network latency

        var sanitized = Uri.EscapeDataString(query);
        return $"""
            Search results for: "{query}"

            1. Title: {query} - Wikipedia
               URL: https://en.wikipedia.org/wiki/{sanitized}
               Snippet: Comprehensive encyclopedia article covering the history, key concepts, and significance of {query}.

            2. Title: Latest Developments in {query} - TechReview
               URL: https://techreview.example.com/articles/{sanitized}
               Snippet: An analysis of recent breakthroughs and trends related to {query}, including expert opinions and data.

            3. Title: Understanding {query}: A Complete Guide
               URL: https://deepdive.example.com/guides/{sanitized}
               Snippet: In-depth guide explaining the fundamentals of {query}, common applications, and best practices.

            4. Title: The Future of {query} - ResearchDigest
               URL: https://researchdigest.example.com/{sanitized}
               Snippet: Forward-looking analysis exploring where {query} is headed, based on current research and industry trends.

            Note: These are simulated results. Replace WebSearchTool.SearchAsync with a real search API for live data.
            """;
    }
}

// =============================================================================
// Research Notebook
// =============================================================================
sealed class ResearchNotebook
{
    private readonly List<NoteEntry> _notes = [];

    public int Count => _notes.Count;

    public void AddNote(string title, string content, string? source)
    {
        _notes.Add(new NoteEntry(title, content, source, DateTime.UtcNow));
    }

    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n" +
            $"Content: {n.Content}\n" +
            (n.Source is not null ? $"Source: {n.Source}\n" : "") +
            $"Saved: {n.Timestamp:u}"));
    }

    public void Clear() => _notes.Clear();

    private sealed record NoteEntry(string Title, string Content, string? Source, DateTime Timestamp);
}

